sections.prose:
Most queries are public (no `Authorization` header). `myPages` requires authentication.

```json
{
  "query": "query ($pageId: String!) { pages { page(pageId: $pageId) { pageId title pageType route status version } } }",
  "variables": { "pageId": "docs-getting-started" }
}
```

code_blocks.value:
{
  "query": "query ($pageId: String!) { pages { page(pageId: $pageId) { pageId title pageType route status version } } }",
  "variables": { "pageId": "docs-getting-started" }
}

type PageList {
  pages: [PageSummary!]!
  total: Int!
}

type PageContent {
  pageId: String!
  content: String!
}

type PageTypeInfo {
  type: String!
  count: Int!
}

type PageTypeList {
  types: [PageTypeInfo!]!
  total: Int!
}

query GetPage($pageId: String!, $pageType: String) {
  pages {
    page(pageId: $pageId, pageType: $pageType) {
      pageId
      title
      pageType
      description
      contentUrl
      route
      status
      version
      category
      updatedAt
    }
  }
}

{
  "data": {
    "pages": {
      "page": {
        "pageId": "getting-started",
        "title": "Getting Started Guide",
        "pageType": "docs",
        "description": "Quick start guide for new users",
        "contentUrl": "https://s3.amazonaws.com/bucket/pages/getting-started.md?...",
        "route": "/docs/getting-started",
        "status": "published",
        "version": 3,
        "category": "guides",
        "updatedAt": "2024-01-15T10:30:00Z"
      }
    }
  }
}

query ListPages(
  $pageType: String
  $includeDrafts: Boolean
  $includeDeleted: Boolean
  $status: String
  $limit: Int
  $offset: Int
) {
  pages {
    pages(
      pageType: $pageType
      includeDrafts: $includeDrafts
      includeDeleted: $includeDeleted
      status: $status
      limit: $limit
      offset: $offset
    ) {
      pages {
        pageId
        title
        pageType
        route
        status
      }
      total
    }
  }
}

{
  "data": {
    "pages": {
      "pages": {
        "pages": [
          {
            "pageId": "getting-started",
            "title": "Getting Started",
            "pageType": "docs",
            "route": "/docs/getting-started",
            "status": "published"
          },
          {
            "pageId": "api-reference",
            "title": "API Reference",
            "pageType": "docs",
            "route": "/docs/api",
            "status": "published"
          }
        ],
        "total": 42
      }
    }
  }
}

